    foot_model: "型号：", foot_spec_chamber: "烹饪室 L100 × Ø50 cm", foot_spec_firebox: "燃烧室 L40 × Ø45 cm · 双层烤架", foot_spec_fuel: "燃料：橡木 + 红树炭",
